   320→                bgInputRef={bgInputRef}
   321→                gradients={gradients}
   322→                handleSelectGradient={handleSelectGradient}
   323→                handleInsertBgImage={handleInsertBgImage}
   324→                imageSrc={imageSrc}
   325→                crop={crop}
   326→                zoom={zoom}
   327→                setCrop={setCrop}
   328→                setZoom={setZoom}
   329→                setCropAreaPixels={setCropAreaPixels}
   330→                handleRemoveBgPreview={handleRemoveBgPreview}
   331→                handleHideGradientPicker={handleHideGradientPicker}
   332→                handleSaveProfileConfig={handleSaveProfileConfig}
   333→                isUpdatingProfileConfig={isUpdatingProfileConfig}
   334→            />
   335→            <AnimatePresence>
   336→                <ProfileEditModal
