   341→                    insertImageFromFile={insertImageFromFile}
   342→                    handleImageOnChange={handleImageOnChange}
   343→                    inputRef={inputRef}
   344→                    editImagePreview={editImagePreview}
   345→                    userData={userData}
   346→                    handleShowGradientPicker={handleShowGradientPicker}
   347→                    profileEditName={profileEditName}
   348→                    setProfileEditName={setProfileEditName}
   349→                    profileEditBio={profileEditBio}
   350→                    setProfileEditBio={setProfileEditBio}
   351→                    handleSaveProfileEdit={handleSaveProfileEdit}
   352→                    isSavingProfile={isSavingProfile}
   353→                />
   354→
   355→                {showEditor && <Editor key={"main-editor"} onClose={handleCloseRichTextEditor} />}
   356→
   357→                <div
   358→                    className="profile-parent-container"
   359→                    style={croppedImage ? { background: `linear-gradient(135deg, ${dominantColors}0%, ${secondaryColors} 100%)` } : gradientPicked}
   360→                >
   361→                    {gradientPicked && <div className="blurred-gradient-bg" style={gradientPicked} />}
   362→
   363→                    {croppedImage && <div style={croppedImage} className="blurred-img-bg" />}
   364→
   365→                    <div className="side-bar-holder-container">
   366→                        <Sidebar links={links} />
   367→                    </div>
   368→
   369→                    <div style={{ color: fontColor || userData?.profile_font_color }} className="profile-center-bar-container">
