   372→                            user={user}
   373→                            fontColor={fontColor}
   374→                            handleClickEdit={handleClickEdit}
   375→                            handleClickFontColorSelector={handleClickFontColorSelector}
   376→                            croppedImage={croppedImage}
   377→                            gradientPicked={gradientPicked}
   378→                        />
   379→
   380→                        <ProfileTabList tablists={tablists} navigate={navigate} location={location} />
   381→
   382→                        <Outlet />
   383→                    </div>
   384→
   385→                    <div className="profile-sidebar-right-holder-container">{/* Log out */}</div>
   386→
   387→                    {showMobileSideBar && <MobileSidebarLink onclose={handleCloseSidebar} />}
   388→
   389→                    <MobileNavlink clickOpenSidebar={handleClickOpenSidebar} />
   390→                    <WriteJournalButton onOpen={opendRichTextEditor} />
