### 2.4 Create Notes Section Component

**New File: `C:\Users\johnm\iskrib_v3\client\src\components\ProfilePage\components\ProfileNotesSection.jsx`**

This component manages all notes for a profile:

```jsx
const ProfileNotesSection = ({ userData, isOwner, onUpdate }) => {
  const [notes, setNotes] = useState(userData?.profile_layout?.notes || []);
  const [editingNoteId, setEditingNoteId] = useState(null);
  const [isSaving, setIsSaving] = useState(false);

  const handleAddNote = () => {
    if (notes.length >= MAX_NOTES_COUNT) {
      alert("Maximum 10 notes allowed");
      return;
    }

    const newNote = {
      id: `note_${crypto.randomUUID()}`,
      order: notes.length,
      content: null,
      containerStyle: DEFAULT_NOTE_CONTAINER_STYLE,
      fontColor: DEFAULT_NOTE_FONT_STYLE.fontColor,
      fontFamily: DEFAULT_NOTE_FONT_STYLE.fontFamily,
      visible: true,
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    };

    const updatedNotes = [...notes, newNote];
    setNotes(updatedNotes);
    saveNotesToBackend(updatedNotes);
  };

  const handleUpdateNote = (noteId, updates) => {
    const updatedNotes = notes.map(n => 
      n.id === noteId 
        ? { ...n, ...updates, updated_at: new Date().toISOString() }
        : n
    );
    setNotes(updatedNotes);
    saveNotesToBackend(updatedNotes);
  };

  const handleDeleteNote = (noteId) => {
    const updatedNotes = notes.filter(n => n.id !== noteId);
    setNotes(updatedNotes);
    saveNotesToBackend(updatedNotes);
  };

  const saveNotesToBackend = async (updatedNotes) => {
    setIsSaving(true);
    const formdata = new FormData();
    const newLayout = {
      ...userData.profile_layout,
      notes: updatedNotes
    };
    formdata.append('profileLayout', JSON.stringify(newLayout));

    try {
      await updateProfileData(formdata, session?.access_token);
      // Invalidate query to refetch
      queryClient.invalidateQueries({ queryKey: ['userData'] });
    } catch (error) {
      console.error("Failed to save notes:", error);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="profile-notes-section">
      {isOwner && (
        <button 
          className="add-note-button"
          onClick={handleAddNote}
          disabled={notes.length >= MAX_NOTES_COUNT || isSaving}
        >
          + Add Note
        </button>
      )}

      <div className="notes-grid">
        {notes
          .filter(n => n.visible || isOwner)
          .sort((a, b) => a.order - b.order)
          .map(note => (
            <NoteContainer
              key={note.id}
              note={note}
              isOwner={isOwner}
              onUpdate={(updates) => handleUpdateNote(note.id, updates)}
              onDelete={() => handleDeleteNote(note.id)}
            />
          ))}
      </div>
    </div>
  );
};
```

