### 5.2 Debounce Strategy

Create a custom hook for debounced note saving:

**New File: `C:\Users\johnm\iskrib_v3\client\src\hooks\useDebounceNoteSave.js`**

```javascript
import { useCallback, useRef } from 'react';
import debounce from '../helpers/debounce';

export const useDebounceNoteSave = (saveFunction, delay = 1000) => {
  const debouncedSave = useRef(
    debounce((notes) => {
      saveFunction(notes);
    }, delay)
  ).current;

  return useCallback((notes) => {
    debouncedSave(notes);
  }, [debouncedSave]);
};
```

