## Phase 6: Read-Only View for Visitors

### 6.1 Create Read-Only Note Viewer

**New File: `C:\Users\johnm\iskrib_v3\client\src\components\ProfilePage\components\ReadOnlyNoteView.jsx`**

This component renders Lexical content in read-only mode:

```jsx
import { LexicalComposer } from '@lexical/react/LexicalComposer';
import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
import { ContentEditable } from '@lexical/react/LexicalContentEditable';
import { HistoryPlugin } from '@lexical/react/LexicalHistoryPlugin';
import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import { useEffect } from 'react';

const LoadContentPlugin = ({ content }) => {
  const [editor] = useLexicalComposerContext();

  useEffect(() => {
    if (content) {
      const editorState = editor.parseEditorState(content);
      editor.setEditorState(editorState);
    }
  }, [content, editor]);

  return null;
};

const ReadOnlyNoteView = ({ content }) => {
  const initialConfig = {
    namespace: 'ReadOnlyNote',
    editable: false,
    nodes: [ImageNode, HeadingNode, QuoteNode],
    theme: {
      paragraph: 'editor-paragraph',
      heading: 'editor-heading',
      // ... theme from App.jsx
    },
    onError: (error) => console.error(error)
  };

  return (
    <LexicalComposer initialConfig={initialConfig}>
      <div className="readonly-note-view">
        <RichTextPlugin
          contentEditable={<ContentEditable className="readonly-content" />}
          placeholder={<div className="placeholder">No content</div>}
          ErrorBoundary={LexicalErrorBoundary}
        />
        <HistoryPlugin />
        <LoadContentPlugin content={content} />
      </div>
    </LexicalComposer>
  );
};
```

